module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const color = args.color || 'var(--accent-color)';
const lines = sections.join('\n').split('\n').map((l) => l.trim()).filter(Boolean);
if (!lines.length) return `<div>(heatmap: rows of numbers, cells split by | )</div>`;
const grid = lines.map((l) => l.split('|').map((c) => c.trim()));
const isNum = (v) => v !== '' && Number.isFinite(parseFloat(v)) && /^-?[\d.]+$/.test(v);
// Column header row = first row with an empty leading cell.
let colHead = null, start = 0;
if (grid[0][0] === '') { colHead = grid[0].slice(1); start = 1; }
const body = grid.slice(start);
// Row labels = first cell if non-numeric across body.
const hasRowLabels = body.some((r) => r.length && !isNum(r[0]));
const nums = [];
body.forEach((r) => { const cells = hasRowLabels ? r.slice(1) : r; cells.forEach((c) => { if (isNum(c)) nums.push(parseFloat(c)); }); });
let lo = args.min !== '' && args.min != null ? parseFloat(args.min) : Math.min(...nums);
let hi = args.max !== '' && args.max != null ? parseFloat(args.max) : Math.max(...nums);
if (!Number.isFinite(lo)) lo = 0; if (!Number.isFinite(hi)) hi = 1; if (hi === lo) hi = lo + 1;
const t = (v) => Math.max(0, Math.min(1, (v - lo) / (hi - lo)));
const cols = Math.max(...body.map((r) => (hasRowLabels ? r.length - 1 : r.length))) + (hasRowLabels ? 1 : 0);
let html = `\n\n<div class="mdp-mod-heatmap" style="--hm-c:${color}; grid-template-columns: repeat(${cols}, auto);">`;
if (colHead) {
  if (hasRowLabels) html += `<div class="mdp-hm-corner"></div>`;
  colHead.forEach((h) => { html += `<div class="mdp-hm-head">${esc(h)}</div>`; });
}
body.forEach((r) => {
  const cells = hasRowLabels ? r.slice(1) : r;
  if (hasRowLabels) html += `<div class="mdp-hm-rowlabel">${esc(r[0])}</div>`;
  cells.forEach((c) => {
    if (isNum(c)) {
      const a = (0.12 + 0.85 * t(parseFloat(c))).toFixed(3);
      html += `<div class="mdp-hm-cell" style="background: color-mix(in srgb, var(--hm-c) ${(a * 100).toFixed(1)}%, transparent);">${esc(c)}</div>`;
    } else {
      html += `<div class="mdp-hm-cell mdp-hm-empty">${esc(c)}</div>`;
    }
  });
});
html += `</div>\n\n`;
return html;
